import React from "react";
import coin from '../img/main-icon.png'
import goldCoin from '../img/logo.png'

class Welcome extends React.Component{
    welcomeText = 'Медная монета'

    state = {
        count: 0,
        mainImg: coin
    }

    render(){
        return(
            <main className="main">
                <section className="welcome">
                    <div className="container">
                        <h1 className="welcome-title">{this.welcomeText}</h1>
                        <img className="welcome-img" src={this.setState.mainImg} onClick={this.click}/>
                        <h2 className="counter">Ваш счет {this.state.count}</h2>
                    </div>
                </section>
            </main>
        )
    }

    click = () =>{
        this.setState({
            count: this.state.count + 10
        })
    }

    changePicture = () =>{
        if(this.state.count > 100){
            this.setState({
                mainImg:goldCoin
            })
            this.welcomeText = 'Золотая монета'
        }
    }
}

export default Welcome
